//go:generate sh -c "set -eu; root=$DOLLAR(cd ../../../.. && pwd); wkt_include=$DOLLAR{PROTOBUF_INCLUDE:-}; if [ -z \"$DOLLAR{wkt_include}\" ]; then wkt_include=$DOLLAR(pkg-config --variable=includedir protobuf 2>/dev/null || true); fi; proto_path_args=\"--proto_path=$DOLLAR{root}/api/rpc\"; if [ -n \"$DOLLAR{wkt_include}\" ]; then proto_path_args=\"$DOLLAR{proto_path_args} --proto_path=$DOLLAR{wkt_include}\"; fi; payload_files=$DOLLAR(find \"$DOLLAR{root}/api/rpc/payload\" -name '*.proto' | sort); protoc --go_out=\"$DOLLAR{root}\" --go_opt=module=github.com/GizClaw/gizclaw-go $DOLLAR{proto_path_args} \"$DOLLAR{root}/api/rpc/common.proto\" \"$DOLLAR{root}/api/rpc/peer.proto\" $DOLLAR{payload_files}"
